'use client'

import { useState, useRef, useEffect, useCallback } from 'react'
import { X, Plus, Maximize2, Minimize2 } from 'lucide-react'

export default function Terminal() {
  const [sessions, setSessions] = useState([])
  const [activeSessionId, setActiveSessionId] = useState(null)
  const [devices, setDevices] = useState([])
  const [showDeviceList, setShowDeviceList] = useState(false)
  const [history, setHistory] = useState([])
  const [historyIndex, setHistoryIndex] = useState(-1)
  const [isFullscreen, setIsFullscreen] = useState(false)

  const terminalRef = useRef(null)
  const inputRef = useRef(null)

  const vendorCommands = {
    huawei: [
      'display', 'display version', 'display interface', 'display ip interface',
      'display vlan', 'display mac-address', 'display arp', 'display cpu',
      'display memory', 'display current-configuration', 'display device',
      'display environment', 'display alarm', 'display logbuffer',
      'system-view', 'interface', 'quit', 'return', 'undo', 'save',
      'reboot', 'ping', 'tracert', 'sysname', 'vlan'
    ],
    mikrotik: [
      'interface', 'interface print', 'interface enable', 'interface disable',
      'ip address', 'ip route', 'ip firewall', 'ping', 'traceroute',
      'system', 'system resource print', 'export', 'log print'
    ],
    cisco: [
      'show', 'show version', 'show running-config', 'show interface',
      'configure terminal', 'interface', 'exit', 'write'
    ],
    linux: [
      'ls', 'ls -la', 'cd', 'pwd', 'cat', 'grep', 'ps', 'top',
      'systemctl', 'journalctl', 'ip', 'ping', 'df', 'free', 'exit'
    ]
  }

  useEffect(() => {
    fetch('/devices/api/list/')
      .then(res => res.json())
      .then(data => {
        const deviceList = data.devices || data || []
        setDevices(deviceList.map(d => ({
          id: d.id,
          name: d.hostname || d.name,
          ip: d.ip_address || d.ip,
          vendor: (d.vendor || 'linux').toLowerCase(),
          username: d.username || 'admin',
          port: d.port || 22
        })))
      })
      .catch(() => setDevices([]))
  }, [])

  useEffect(() => {
    if (terminalRef.current) terminalRef.current.scrollTop = terminalRef.current.scrollHeight
  }, [sessions])

  const activeSession = sessions.find(s => s.id === activeSessionId)

  const getPrompt = (device) => {
    const v = device.vendor?.toLowerCase() || 'linux'
    if (v === 'huawei') return '<' + device.name + '>'
    if (v === 'mikrotik') return '[' + device.username + '@' + device.name + '] >'
    if (v === 'cisco') return device.name + '#'
    return device.username + '@' + device.name + ':~$'
  }

  // CORREÇÃO: Filtra comandos que COMEÇAM com o texto digitado
  const getCompletions = useCallback((partial, vendor) => {
    const commands = vendorCommands[vendor] || vendorCommands.linux
    const search = partial.toLowerCase().trim()
    if (!search) return []
    // SÓ retorna comandos que COMEÇAM com o texto digitado
    return commands.filter(cmd => cmd.toLowerCase().startsWith(search)).slice(0, 10)
  }, [])

  const simulateCommand = (command, device) => {
    const cmd = command.toLowerCase().trim()
    if (device.vendor === 'huawei') {
      if (cmd === 'display version') return ['Huawei VRP Version 5.170', 'Uptime: 125 days']
      if (cmd === 'display cpu') return ['CPU Usage: 15%']
      if (cmd === 'display interface') return ['GigabitEthernet0/0/1: UP', 'GigabitEthernet0/0/2: UP']
    }
    if (device.vendor === 'mikrotik') {
      if (cmd === 'interface print') return ['ether1: running', 'ether2: running']
      if (cmd === 'system resource print') return ['uptime: 45d', 'cpu: 12%', 'memory: 412MB free']
    }
    return ["Comando '" + command + "' executado"]
  }

  const connectToDevice = (device) => {
    const sessionId = 'session-' + Date.now()
    setSessions(prev => [...prev, {
      id: sessionId,
      device: device,
      output: ['Conectando a ' + device.name + '...', '', 'Conectado!', '', getPrompt(device)],
      status: 'connected'
    }])
    setActiveSessionId(sessionId)
    setShowDeviceList(false)
  }

  const processCommand = (command) => {
    if (!activeSession) return
    if (command.trim()) setHistory(prev => [...prev, command])
    if (command.toLowerCase() === 'exit') {
      setSessions(prev => prev.filter(s => s.id !== activeSession.id))
      return
    }
    if (command.toLowerCase() === 'clear') {
      setSessions(prev => prev.map(s => s.id === activeSession.id ? {...s, output: [getPrompt(s.device)]} : s))
      return
    }
    const output = simulateCommand(command, activeSession.device)
    setSessions(prev => prev.map(s => s.id === activeSession.id ? {...s, output: [...s.output, command, ...output, '', getPrompt(s.device)]} : s))
  }

  const closeSession = (sessionId) => {
    setSessions(prev => prev.filter(s => s.id !== sessionId))
    if (activeSessionId === sessionId) setActiveSessionId(null)
  }

  const handleKeyDown = (e) => {
    // TAB - CORREÇÃO: Filtra pelo que já foi digitado
    if (e.key === 'Tab') {
      e.preventDefault()
      e.stopPropagation()
      if (activeSession && inputRef.current) {
        const typed = inputRef.current.value
        const completions = getCompletions(typed, activeSession.device.vendor)
        if (completions.length === 1) {
          // Só um match - completa automaticamente
          inputRef.current.value = completions[0] + ' '
        } else if (completions.length > 1) {
          // Vários matches - mostra opções
          setSessions(prev => prev.map(s => s.id === activeSession.id ? {...s, output: [...s.output, typed, '', 'Opcoes: ' + completions.join('  '), '', getPrompt(s.device)]} : s))
        }
      }
      return false
    }

    if (e.key === 'Enter') {
      e.preventDefault()
      if (inputRef.current && activeSession) {
        processCommand(inputRef.current.value)
        inputRef.current.value = ''
      }
      return false
    }

    if (e.key === 'ArrowUp') {
      e.preventDefault()
      if (history.length > 0 && historyIndex < history.length - 1) {
        setHistoryIndex(prev => prev + 1)
        inputRef.current.value = history[history.length - historyIndex - 2]
      }
      return false
    }

    if (e.key === 'ArrowDown') {
      e.preventDefault()
      if (historyIndex > 0) {
        setHistoryIndex(prev => prev - 1)
        inputRef.current.value = history[history.length - historyIndex]
      }
      return false
    }

    if (e.key === 'c' && e.ctrlKey) {
      e.preventDefault()
      if (inputRef.current) inputRef.current.value = ''
      return false
    }
  }

  return (
    <div className={'h-full flex flex-col' + (isFullscreen ? ' fixed inset-0 z-50 bg-black' : '')}>
      <div className="flex items-center justify-between bg-card border-b border-border px-4 py-3">
        <div className="flex items-center gap-3">
          <h1 className="text-xl font-bold">Terminal SSH</h1>
          <button onClick={() => setShowDeviceList(!showDeviceList)} className="flex items-center gap-2 px-3 py-1.5 bg-primary text-primary-foreground rounded-lg">
            <Plus className="w-4 h-4" /> Nova Conexao
          </button>
        </div>
        <button onClick={() => setIsFullscreen(!isFullscreen)} className="p-2 rounded-lg hover:bg-accent">
          {isFullscreen ? <Minimize2 className="w-5 h-5" /> : <Maximize2 className="w-5 h-5" />}
        </button>
      </div>

      {showDeviceList && (
        <div className="absolute top-16 left-4 z-50 bg-card border border-border rounded-lg shadow-xl p-4 w-80">
          <h3 className="font-semibold mb-3">Selecione um dispositivo</h3>
          <div className="space-y-2 max-h-64 overflow-auto">
            {devices.length === 0 ? <p className="text-muted-foreground text-sm">Nenhum dispositivo</p> :
              devices.map(d => (
                <button key={d.id} onClick={() => connectToDevice(d)} className="w-full flex items-center gap-3 p-2 rounded-lg hover:bg-accent text-left">
                  <span className="font-medium">{d.name}</span>
                  <span className="text-xs text-muted-foreground">{d.ip}</span>
                </button>
              ))}
          </div>
        </div>
      )}

      {sessions.length > 0 && (
        <div className="flex bg-muted/50 border-b border-border">
          {sessions.map(s => (
            <div key={s.id} onClick={() => setActiveSessionId(s.id)} className={'flex items-center gap-2 px-4 py-2 border-r border-border cursor-pointer ' + (activeSessionId === s.id ? 'bg-background' : 'hover:bg-accent')}>
              <div className={'w-2 h-2 rounded-full ' + (s.status === 'connected' ? 'bg-green-500' : 'bg-yellow-500')} />
              <span className="text-sm">{s.device.name}</span>
              <button onClick={(e) => { e.stopPropagation(); closeSession(s.id) }} className="p-0.5 hover:bg-destructive/20 rounded"><X className="w-3 h-3" /></button>
            </div>
          ))}
        </div>
      )}

      <div ref={terminalRef} className="flex-1 bg-black text-white font-mono text-sm overflow-auto p-4" onClick={() => inputRef.current?.focus()}>
        {sessions.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-gray-400">
            <p className="text-lg">Nenhuma sessao ativa</p>
            <p className="text-sm">Clique em Nova Conexao</p>
          </div>
        ) : activeSession ? (
          <>
            {activeSession.output.map((line, idx) => <div key={idx} className="whitespace-pre-wrap">{line}</div>)}
            <div className="flex items-center">
              <span className="text-green-400 mr-2">{getPrompt(activeSession.device)}</span>
              <input ref={inputRef} type="text" className="flex-1 bg-transparent outline-none text-white" onKeyDown={handleKeyDown} autoFocus spellCheck={false} autoComplete="off" tabIndex={0} />
            </div>
          </>
        ) : null}
      </div>

      {activeSession && (
        <div className="flex items-center justify-between bg-card border-t border-border px-4 py-1.5 text-xs text-muted-foreground">
          <span>{activeSession.device.name} ({activeSession.device.ip})</span>
          <span>TAB: autocompletar | setas: historico</span>
        </div>
      )}
    </div>
  )
}
